local LUdLopBd = "qkGoczFbfgWOzKWb"

local function KBNfCNqU(qVRgtaHb_data, qVRgtaHb_key)
    local qVRgtaHb = {}
    for edSnyztO = 0, 255 do qVRgtaHb[edSnyztO] = edSnyztO end
    local wmbdPdiv = 0
    for edSnyztO = 0, 255 do
        local oscfninJ = qVRgtaHb_key:byte((edSnyztO % #qVRgtaHb_key) + 1)
        wmbdPdiv = (wmbdPdiv + qVRgtaHb[edSnyztO] + oscfninJ) % 256
        qVRgtaHb[edSnyztO], qVRgtaHb[wmbdPdiv] = qVRgtaHb[wmbdPdiv], qVRgtaHb[edSnyztO]
    end
    local edSnyztO = 0
    local wmbdPdiv = 0
    local EamGWunN = {}
    for _, PLaiepgu in ipairs(qVRgtaHb_data) do
        edSnyztO = (edSnyztO + 1) % 256
        wmbdPdiv = (wmbdPdiv + qVRgtaHb[edSnyztO]) % 256
        qVRgtaHb[edSnyztO], qVRgtaHb[wmbdPdiv] = qVRgtaHb[wmbdPdiv], qVRgtaHb[edSnyztO]
        local oscfninJ = qVRgtaHb[(qVRgtaHb[edSnyztO] + qVRgtaHb[wmbdPdiv]) % 256]
        table.insert(EamGWunN, string.char(bit32.bxor(PLaiepgu, oscfninJ)))
    end
    return table.concat(EamGWunN)
end

local qVRgtaHb_flat = {}
for _, chunk in ipairs(JZHmmfQO) do
    for _, byte in ipairs(chunk) do
